    public static IHtmlContent Ikon(this IHtmlHelper _, string nama, string css = "icon")
    {
        var isi = Paths.TryGetValue(nama, out var p) ? p : string.Empty;
        var svg = $"<svg class=\"{css}\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" " +
                  "stroke-width=\"1.5\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">" +
                  isi + "</svg>";
        return new HtmlString(svg);
    }
